import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { 
  FaUser, 
  FaUserMd, 
  FaPills, 
  FaEye, 
  FaEyeSlash, 
  FaSpinner, 
  FaHeartbeat,
  FaArrowLeft,
  FaLock
} from 'react-icons/fa';

const Login = ({ onLogin }) => {
  const { t, i18n } = useTranslation();
  const [selectedRole, setSelectedRole] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [step, setStep] = useState('role'); // role, credentials
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');

  const roles = [
    {
      id: 'doctor',
      name: 'Doctor',
      icon: '👨‍⚕️',
      gradient: 'from-sky-400 to-cyan-500',
      bgHover: 'hover:from-sky-500 hover:to-cyan-600',
      sampleUsername: 'd001',
      color: 'text-sky-600'
    },
    {
      id: 'patient',
      name: 'Patient',
      gradient: 'from-red-400 to-orange-500',
      bgHover: 'hover:from-red-500 hover:to-orange-600',
      icon: '👤',
      sampleUsername: 'p001',
      color: 'text-red-600'
    },
    {
      id: 'pharmacist',
      name: 'Pharmacist',
      gradient: 'from-emerald-400 to-pink-400',
      bgHover: 'hover:from-emerald-500 hover:to-pink-500',
      icon: '💊',
      sampleUsername: 'pm001',
      color: 'text-emerald-600'
    }
  ];

  const handleRoleSelect = (role) => {
    setSelectedRole(role);
    setStep('credentials');
    setError('');
    setUsername('');
    setPassword('');
  };

  const handleLogin = async () => {
    if (!username || !password) {
      setError('Please enter both username and password');
      return;
    }
    
    setIsLoading(true);
    setError('');
    
    try {
      console.log('🔐 Attempting login with:', { username, role: selectedRole });
      
      const payload = {
        username: username,
        password: password
      };
      
      const response = await fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload)
      });
      
      console.log('📡 Response status:', response.status);
      
      let data = {};
      try {
        data = await response.json();
      } catch (e) {
        console.error('Failed to parse JSON response');
      }
      console.log('📄 Response data:', data);
      
      if (response.ok) {
        const token = data.token || data.access_token;
        const user = data.user || {
          id: data.id || data.user_id,
          role: data.role || data.user_type,
          username: data.username || username,
        };
        
        if (!token) {
          throw new Error('Missing token in response');
        }
        
        localStorage.setItem('token', token);
        localStorage.setItem('user', JSON.stringify(user));
        
        console.log('✅ Login successful, redirecting...');
        
        onLogin({
          ...user,
          token
        });
      } else {
        console.error('❌ Login failed:', data);
        const serverMsg = data?.message || data?.error || 'Login failed';
        setError(serverMsg);
      }
    } catch (err) {
      console.error('🚨 Login error:', err);
      if (err.name === 'TypeError' && err.message.includes('fetch')) {
        setError('Unable to connect to server. Please ensure the backend is running on http://localhost:5000');
      } else {
        setError('Network error. Please check your connection and try again.');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const getCurrentRole = () => {
    return roles.find(role => role.id === selectedRole);
  };

  const handleBack = () => {
    setStep('role');
    setSelectedRole('');
    setError('');
    setUsername('');
    setPassword('');
  };

  const getPasswordForRole = (role) => {
    switch(role) {
      case 'patient': return 'patient123';
      case 'doctor': return 'doctor123';
      case 'pharmacist': return 'pharmacy123';
      default: return '';
    }
  };

  const fillSampleCredentials = () => {
    const role = getCurrentRole();
    if (role) {
      setUsername(role.sampleUsername);
      setPassword(getPasswordForRole(selectedRole));
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 flex flex-col">
      {/* Main Content */}
      <div className="flex-1 flex items-center justify-center p-4">
        <div className="w-full max-w-md">
          
          {/* Step 1: Role Selection */}
          {step === 'role' && (
            <div className="space-y-8">
              {/* Hero Section */}
              <div className="text-center space-y-4">
                <div className="w-16 h-16 bg-gradient-to-r from-blue-500 to-purple-600 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg">
                  <FaHeartbeat className="text-white text-2xl" />
                </div>
                <h1 className="text-3xl font-bold text-gray-800 tracking-tight">
                  Helio Healthcare Platform
                </h1>
                <p className="text-xl text-gray-600 font-medium">
                  Choose Your Role
                </p>
              </div>

              {/* Role Selection Buttons */}
              <div className="space-y-4">
                {roles.map((role) => (
                  <button
                    key={role.id}
                    onClick={() => handleRoleSelect(role.id)}
                    className={`w-full p-6 bg-gradient-to-r ${role.gradient} ${role.bgHover} text-white rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300 transform hover:scale-[1.02] active:scale-95`}
                  >
                    <div className="flex items-center space-x-4">
                      <span className="text-3xl">{role.icon}</span>
                      <span className="text-xl font-bold">{role.name}</span>
                    </div>
                  </button>
                ))}
              </div>

              {/* Demo Credentials Section */}
              <div className="bg-white rounded-2xl p-6 shadow-lg border border-gray-100">
                <h3 className="text-lg font-bold text-gray-800 mb-4 text-center">Demo Credentials</h3>
                
                {/* Sample Usernames */}
                <div className="space-y-3 mb-6">
                  <div className="flex justify-between items-center p-3 bg-sky-50 rounded-xl border border-sky-100">
                    <div className="flex items-center space-x-2">
                      <span className="text-xl">👨‍⚕️</span>
                      <span className="font-semibold text-sky-700">Doctors:</span>
                    </div>
                    <span className="text-sm font-mono bg-sky-100 px-3 py-1 rounded-lg text-sky-800">d001, d002, d003</span>
                  </div>
                  
                  <div className="flex justify-between items-center p-3 bg-red-50 rounded-xl border border-red-100">
                    <div className="flex items-center space-x-2">
                      <span className="text-xl">👤</span>
                      <span className="font-semibold text-red-700">Patients:</span>
                    </div>
                    <span className="text-sm font-mono bg-red-100 px-3 py-1 rounded-lg text-red-800">p001, p002, p003</span>
                  </div>
                  
                  <div className="flex justify-between items-center p-3 bg-emerald-50 rounded-xl border border-emerald-100">
                    <div className="flex items-center space-x-2">
                      <span className="text-xl">💊</span>
                      <span className="font-semibold text-emerald-700">Pharmacists:</span>
                    </div>
                    <span className="text-sm font-mono bg-emerald-100 px-3 py-1 rounded-lg text-emerald-800">pm001, pm002, pm003</span>
                  </div>
                </div>

                {/* Default Passwords */}
                <div className="bg-gray-50 rounded-xl p-4 border border-gray-200">
                  <div className="flex items-center space-x-2 mb-3">
                    <FaLock className="text-gray-600" />
                    <span className="font-bold text-gray-800">Default Passwords</span>
                  </div>
                  <div className="space-y-2 text-sm">
                    <div className="flex items-center justify-between p-2 bg-white rounded-lg border">
                      <span className="flex items-center space-x-2">
                        <span>👤</span>
                        <span className="font-semibold">Patient:</span>
                        <span className="font-mono text-red-600">p001</span>
                      </span>
                      <span className="font-mono font-bold text-red-600">patient123</span>
                    </div>
                    <div className="flex items-center justify-between p-2 bg-white rounded-lg border">
                      <span className="flex items-center space-x-2">
                        <span>👨‍⚕️</span>
                        <span className="font-semibold">Doctor:</span>
                        <span className="font-mono text-sky-600">d001</span>
                      </span>
                      <span className="font-mono font-bold text-sky-600">doctor123</span>
                    </div>
                    <div className="flex items-center justify-between p-2 bg-white rounded-lg border">
                      <span className="flex items-center space-x-2">
                        <span>💊</span>
                        <span className="font-semibold">Pharmacist:</span>
                        <span className="font-mono text-emerald-600">pm001</span>
                      </span>
                      <span className="font-mono font-bold text-emerald-600">pharmacy123</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Step 2: Login Credentials */}
          {step === 'credentials' && (
            <div className="space-y-6">
              {/* Header */}
              <div className="text-center space-y-4">
                <div className={`w-20 h-20 bg-gradient-to-r ${getCurrentRole()?.gradient} rounded-2xl flex items-center justify-center mx-auto shadow-lg`}>
                  <span className="text-3xl">{getCurrentRole()?.icon}</span>
                </div>
                <h2 className="text-2xl font-bold text-gray-800">
                  {getCurrentRole()?.name} Login
                </h2>
                <p className="text-gray-600">Enter your credentials to continue</p>
              </div>

              {/* Error Message */}
              {error && (
                <div className="bg-red-50 border border-red-200 rounded-xl p-4">
                  <div className="flex items-center space-x-2">
                    <span className="text-red-500 font-bold">⚠️</span>
                    <span className="text-red-700 font-medium">{error}</span>
                  </div>
                </div>
              )}

              {/* Login Form */}
              <div className="bg-white rounded-2xl p-6 shadow-lg border border-gray-100 space-y-6">
                {/* Username Field */}
                <div className="space-y-2">
                  <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide">
                    Username
                  </label>
                  <input
                    type="text"
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    placeholder={`e.g., ${getCurrentRole()?.sampleUsername}`}
                    className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-200 text-lg"
                    disabled={isLoading}
                  />
                </div>

                {/* Password Field */}
                <div className="space-y-2">
                  <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide">
                    Password
                  </label>
                  <div className="relative">
                    <input
                      type={showPassword ? 'text' : 'password'}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      placeholder="Enter your password"
                      className="w-full px-4 py-3 pr-12 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-200 text-lg"
                      disabled={isLoading}
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-500 hover:text-gray-700"
                    >
                      {showPassword ? <FaEyeSlash size={20} /> : <FaEye size={20} />}
                    </button>
                  </div>
                </div>

                {/* Quick Fill Button */}
                <button
                  onClick={fillSampleCredentials}
                  className="w-full p-3 bg-gray-100 text-gray-700 rounded-xl hover:bg-gray-200 transition-colors duration-200 font-medium"
                  disabled={isLoading}
                >
                  Quick Fill Demo ({getCurrentRole()?.sampleUsername})
                </button>

                {/* Action Buttons */}
                <div className="flex space-x-3 pt-4">
                  <button
                    onClick={handleBack}
                    className="flex-1 py-3 px-4 border border-gray-300 rounded-xl text-gray-700 font-semibold hover:bg-gray-50 transition-colors duration-200 flex items-center justify-center space-x-2"
                    disabled={isLoading}
                  >
                    <FaArrowLeft />
                    <span>Back</span>
                  </button>
                  <button
                    onClick={handleLogin}
                    disabled={isLoading || !username || !password}
                    className={`flex-1 py-3 px-4 bg-gradient-to-r ${getCurrentRole()?.gradient} text-white rounded-xl font-semibold hover:opacity-90 disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-200 flex items-center justify-center space-x-2`}
                  >
                    {isLoading ? (
                      <>
                        <FaSpinner className="animate-spin" />
                        <span>Signing in...</span>
                      </>
                    ) : (
                      <span>Sign In</span>
                    )}
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Login;
